# Day 35: DSA: Recursion Fundamentals and Base Cases
# Recursion Fundamentals

# Factorial
def factorial(n):
    if n <= 1: return 1      # base case
    return n * factorial(n-1)  # recursive case

print(f"5! = {factorial(5)}")  # 120

# Fibonacci
def fib(n):
    if n <= 1: return n
    return fib(n-1) + fib(n-2)

print(f"fib(10) = {fib(10)}")  # 55

# Sum of list (recursive)
def rec_sum(lst):
    if not lst: return 0
    return lst[0] + rec_sum(lst[1:])

print(f"Sum: {rec_sum([1,2,3,4,5])}")  # 15

# Binary search (recursive)
def rec_binary_search(arr, target, lo, hi):
    if lo > hi: return -1
    mid = (lo + hi) // 2
    if arr[mid] == target: return mid
    elif arr[mid] < target: return rec_binary_search(arr, target, mid+1, hi)
    else: return rec_binary_search(arr, target, lo, mid-1)

arr = [1,3,5,7,9,11]
print(f"Find 7: {rec_binary_search(arr, 7, 0, len(arr)-1)}")
